// JWT guard — lightweight token presence check.
// Full JWT signature verification activates when PR #162 merges and
// JWT_SECRET + jsonwebtoken are available in the n8n runner env.
// Until then, this guards against unauthenticated calls by requiring
// a non-empty Authorization Bearer token or a body.token field.
const src = $input.first().json;
const headers = src.headers || {};
const body = src.body || src;

// Accept token from Authorization header OR body.token (BackOffice sends header)
const authHeader = (headers.authorization || headers.Authorization || '').toString();
const tokenFromHeader = authHeader.startsWith('Bearer ') ? authHeader.slice(7).trim() : authHeader.trim();
const tokenFromBody = (body.token || '').toString().trim();
const token = tokenFromHeader || tokenFromBody;

if (!token || token.length < 10) {
  // Return 401 through the Respond node — throw stops further execution
  // and n8n's error output sends a 500 by default, so we set a flag instead.
  // We pass the raw input through with an __authError flag for the next node.
  return [{ json: { __authError: true, error: 'Unauthorized', status: 401 } }];
}

// Token present — pass original input downstream
return [{ json: { ...src, __authError: false } }];

// Gate: block if auth failed
const src = $input.first().json;
if (src.__authError) return [];
// Admite filtros opcionales: status, limit, search (email/nombre)
const body = src.body || src;
const status = (body.status || '').toString().trim();
const search = (body.search || '').toString().trim();
const limit = Math.min(500, Math.max(1, Number(body.limit || 100)));
return [{ json: { status, search: search ? `%${search.toLowerCase()}%` : '', limit } }];
